#include <iostream>
#include <cmath>
#include <iomanip>
#include <vector>

class Shape {
public:
    virtual double calculateArea() const {
        return 0.0;
    }
    virtual ~Shape() {}
};

class Circle : public Shape {
private:
    double radius;

public:
    Circle(double r) : radius(r) {}

    double calculateArea() const override {
        return M_PI * radius * radius;
    }
};

class Rectangle : public Shape {
private:
    double width;
    double height;

public:
    Rectangle(double w, double h) : width(w), height(h) {}

    double calculateArea() const override {
        return width * height;
    }
};

int main() {
    std::cout << std::fixed << std::setprecision(4);

    std::vector<Shape*> shapes;

    Circle circle1(5.0);
    Rectangle rectangle1(4.0, 6.0);
    Circle circle2(3.0);
    Rectangle rectangle2(7.0, 2.0);

    shapes.push_back(&circle1);
    shapes.push_back(&rectangle1);
    shapes.push_back(&circle2);
    shapes.push_back(&rectangle2);

    std::cout << "Calculating areas using polymorphism (via Shape pointers):" << std::endl;
    for (const Shape* s : shapes) {
        std::cout << "Area: " << s->calculateArea() << std::endl;
    }

    std::cout << "\nDirect object calls:" << std::endl;
    Circle c_direct(10.0);
    Rectangle r_direct(8.0, 5.0);
    std::cout << "Area of Circle (radius 10.0): " << c_direct.calculateArea() << std::endl;
    std::cout << "Area of Rectangle (width 8.0, height 5.0): " << r_direct.calculateArea() << std::endl;

    return 0;
}
